# platform_telemetry.py — emit DevEx metrics from platform CLI hooks
import time
from datadog import initialize, statsd
from functools import wraps
from typing import Callable
import os

initialize(api_key=os.environ["DD_API_KEY"], host_name="platform-cli")

def track_command(command_name: str):
    """Decorator that records duration and success/failure for any CLI command."""
    def decorator(fn: Callable):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            tags = [
                f"command:{command_name}",
                f"team:{os.environ.get('PLATFORM_TEAM', 'unknown')}",
                f"env:{os.environ.get('ENV', 'dev')}",
            ]
            start = time.monotonic()
            try:
                result = fn(*args, **kwargs)
                statsd.increment("platform.command.success", tags=tags)
                return result
            except Exception as exc:
                statsd.increment("platform.command.failure", tags=tags + [f"error:{type(exc).__name__}"])
                raise
            finally:
                elapsed = (time.monotonic() - start) * 1000
                statsd.histogram("platform.command.duration_ms", elapsed, tags=tags)
        return wrapper
    return decorator

@track_command("scaffold")
def scaffold_project(template: str, output_dir: str) -> str:
    """Create a new agent project from a scaffold template."""
    # ... scaffold logic
    return output_dir

@track_command("deploy")
def deploy_agent(agent_dir: str, env: str) -> dict:
    """Deploy an agent to the target environment."""
    # ... deploy logic
    return {"status": "deployed"}

# survey_bot.py — Slack bot that sends contextual micro-surveys after platform events
import os
from slack_sdk import WebClient
from slack_sdk.errors import SlackApiError

slack = WebClient(token=os.environ["SLACK_BOT_TOKEN"])

NPS_BLOCKS = [
    {
        "type": "section",
        "text": {"type": "mrkdwn", "text": ":clipboard: *Quick platform feedback* (30 sec)"},
    },
    {
        "type": "section",
        "text": {"type": "mrkdwn", "text": "How likely are you to recommend the AI platform to a teammate?"},
    },
    {
        "type": "actions",
        "elements": [
            {
                "type": "button",
                "text": {"type": "plain_text", "text": str(score)},
                "value": f"nps_{score}",
                "action_id": f"nps_score_{score}",
            }
            for score in range(0, 11)
        ],
    },
]

def send_nps_survey(user_slack_id: str, trigger_event: str) -> None:
    """Send a 1-question NPS survey to a developer after a platform event."""
    try:
        slack.chat_postMessage(
            channel=user_slack_id,
            text="Quick platform feedback",
            blocks=NPS_BLOCKS,
            metadata={"event_type": "devex_nps", "trigger": trigger_event},
        )
    except SlackApiError as exc:
        print(f"Slack error: {exc.response['error']}")

