# analyze_survey.py — normalize and score quarterly DevEx survey responses
import json
import statistics
from dataclasses import dataclass, field
from typing import List

@dataclass
class SurveyResponse:
    respondent_id: str  # pseudonymous: "team:infra|role:senior"
    satisfaction: int       # 1–5
    speed_rating: int       # 1–5: "How fast can you go from idea to deployed agent?"
    effectiveness: int      # 1–5: "Can you accomplish your work without constant platform help?"
    quality_trust: int      # 1–5: "Do you trust the platform won't break your deploy?"
    biggest_friction: str   # free-text
    nps: int                # 0–10

@dataclass
class SpaceDimension:
    name: str
    scores: List[float] = field(default_factory=list)

    @property
    def mean(self) -> float:
        return statistics.mean(self.scores) if self.scores else 0.0

    @property
    def percentile_25(self) -> float:
        if not self.scores:
            return 0.0
        sorted_scores = sorted(self.scores)
        idx = max(0, int(len(sorted_scores) * 0.25) - 1)
        return sorted_scores[idx]

def compute_nps(responses: List[SurveyResponse]) -> float:
    promoters = sum(1 for r in responses if r.nps >= 9)
    detractors = sum(1 for r in responses if r.nps <= 6)
    total = len(responses)
    if total == 0:
        return 0.0
    return ((promoters - detractors) / total) * 100

def score_survey(responses: List[SurveyResponse]) -> dict:
    dims = {
        "satisfaction": SpaceDimension("Satisfaction"),
        "speed": SpaceDimension("Speed"),
        "effectiveness": SpaceDimension("Effectiveness"),
        "quality": SpaceDimension("Quality"),
    }
    for r in responses:
        dims["satisfaction"].scores.append(r.satisfaction)
        dims["speed"].scores.append(r.speed_rating)
        dims["effectiveness"].scores.append(r.effectiveness)
        dims["quality"].scores.append(r.quality_trust)

    return {
        "nps": round(compute_nps(responses), 1),
        "dimensions": {k: round(v.mean, 2) for k, v in dims.items()},
        "p25_effectiveness": round(dims["effectiveness"].percentile_25, 2),
        "friction_themes": [r.biggest_friction for r in responses if r.biggest_friction],
        "n": len(responses),
    }
